import{_ as o,o as a,c as l,ah as i}from"./chunks/framework.DsjyFzT5.js";const c="/assets/vim-help.BCEsvMJV.png",m=JSON.parse('{"title":"Vim 概览","description":"","frontmatter":{"title":"Vim 概览","date":"2022-05-12T00:00:00.000Z","category":"Shell","tags":["Vim","Shell","Wiki"]},"headers":[],"relativePath":"_post/ide-skill/vim/vim.md","filePath":"_post/ide-skill/vim/vim.md"}'),d={name:"_post/ide-skill/vim/vim.md"};function t(r,e,s,n,p,h){return a(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="vim-概览" tabindex="-1">Vim 概览 <a class="header-anchor" href="#vim-概览" aria-label="Permalink to &quot;Vim 概览&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>vim 模式：</p><blockquote><p>理解：vim接口本身是一种编程</p></blockquote><h3 id="查看帮助" tabindex="-1">查看帮助 <a class="header-anchor" href="#查看帮助" aria-label="Permalink to &quot;查看帮助&quot;">​</a></h3><ul><li><code>tldr vim</code></li><li><code>man vim</code></li><li>命令模式下输入<code>:help &lt;参数&gt;</code>, 可以通过前缀进一步指定上下文， 更多上下文及说明参见 <a href="https://yianwillis.github.io/vimcdoc/doc/usr_02.html#help-summary" target="_blank" rel="noreferrer">help-summary</a></li></ul><p><img src="'+c+`" alt=""></p><h2 id="正常模式" tabindex="-1">正常模式 <a class="header-anchor" href="#正常模式" aria-label="Permalink to &quot;正常模式&quot;">​</a></h2><ul><li><code>u</code>： 撤销你做的<strong>最后一次</strong>更改（编辑模式下的全部内容，或可视模式下的删除、替换等）</li><li><code>ctrl r</code>: redo</li></ul><h3 id="移动" tabindex="-1">移动 <a class="header-anchor" href="#移动" aria-label="Permalink to &quot;移动&quot;">​</a></h3><p>详见<a href="https://yianwillis.github.io/vimcdoc/doc/quickref.html#quickref" target="_blank" rel="noreferrer">官方中文文档</a>非常详细</p><ul><li><code>hjkl</code>: 左下上右</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  k</span></span>
<span class="line"><span>h    l </span></span>
<span class="line"><span>  j</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><code>w</code>(word): 光标向后移动一个词</li><li><code>b</code>（backward）: 光标向前移动一个词</li><li><code>e</code>（end）: 光标移动到单词末尾，已在末尾则移动到下个词尾</li><li><code>0</code>: 移动到行首</li><li><code>$</code>: 移动到行尾</li><li><code>^</code>: 移动到行中第一个非空</li><li><code>ctrl u</code>: 向上滚动（约半屏）</li><li><code>ctrl d</code>: 向下滚动（约半屏）</li><li><code>G(大写)</code>: 滚动到尾</li><li><code>f 2</code>: 找到后面的2</li><li><code>F 2</code>: 找到前面的2</li><li><code>t 2</code>: 找到后面的2，光标停在2前面</li><li><code>T 2</code>: 找到前面的2，光标停在2后面</li><li><code>%</code>: 如过当前光标停留不同类型的分组上，如（)，[],可使用<code>%</code>在匹配的括号之间来回跳转</li><li><code>;</code>: 重复前次 &quot;f&quot;、&quot;F&quot;、&quot;t&quot; 或 &quot;T&quot; 命令</li><li><code>,</code>: 以相反方向重复前次 &quot;f&quot;、&quot;F&quot;、&quot;t&quot; 或 &quot;T&quot; 命令</li></ul><h3 id="编辑" tabindex="-1">编辑 <a class="header-anchor" href="#编辑" aria-label="Permalink to &quot;编辑&quot;">​</a></h3><ul><li><code>x</code>: 删除当前字符</li><li><code>r 2</code>: 替换当前选中字符为2</li><li><code>~</code>: 大小写转换</li><li></li></ul><p><strong>d: 删除</strong></p><blockquote><p>尝试与上面移动键组合</p></blockquote><ul><li><code>o</code>: 在当前行的下一行进入编辑模式</li><li><code>d w</code>: 删除后面一个单词</li><li><code>d b</code>: 删除前一个单词</li><li><code>d d</code>: 删除当前行</li></ul><p><strong>c(change): 删除并编辑</strong></p><blockquote><p>尝试与上面移动键组合,它会删除从当前位置到光标移动到的目标位置 的全部内容。</p></blockquote><ul><li><code>c c</code>: 删除当前行，光标移动到行首进入编辑模式</li></ul><p><strong>y: 复制</strong>****</p><blockquote><p>尝试与上面移动键组合,它会复制从当前位置到光标移动到的目标位置 的全部内容。</p></blockquote><p><strong>p：粘贴</strong></p><h3 id="计数" tabindex="-1">计数 <a class="header-anchor" href="#计数" aria-label="Permalink to &quot;计数&quot;">​</a></h3><p>尝试与上面编辑、移动符号组合</p><p><code>d4d</code>: 删除4行</p><p><code>5j</code>: 向下移动5行</p><p><code>d5w</code>: 删除5个词</p><h3 id="修饰符" tabindex="-1">修饰符 <a class="header-anchor" href="#修饰符" aria-label="Permalink to &quot;修饰符&quot;">​</a></h3><p><code>i</code>: inside</p><p><code>a</code> 整体</p><p>eg：</p><p><code>ci(</code>: 删除光标()中的内容，进入编辑模式</p><p><code>c%</code>: 如当前光标停留在（，删除()及()中的内容</p><p><code>da(</code>: 删除光标所在，被()包裹的内容</p><h2 id="可视模式" tabindex="-1">可视模式 <a class="header-anchor" href="#可视模式" aria-label="Permalink to &quot;可视模式&quot;">​</a></h2><p>正常模式按 <code>v</code> 进入，按移动键选择</p><h2 id="visual-block-模式" tabindex="-1">VISUAL BLOCK 模式 <a class="header-anchor" href="#visual-block-模式" aria-label="Permalink to &quot;VISUAL BLOCK 模式&quot;">​</a></h2><p>正常模式按<code>ctrl v</code>进入，按移动键选择，跨行选择矩形文本块</p><h2 id="命令模式" tabindex="-1">命令模式 <a class="header-anchor" href="#命令模式" aria-label="Permalink to &quot;命令模式&quot;">​</a></h2><p>正常模式按<code>:</code>进入</p><p><code>:tabnew</code>: 新建tab</p><p><code>:/关键词</code>：搜索关键词，光标跳转到关键词处</p><p><code>:set mouse=a</code>: 启动对鼠标的支持</p><p><code>:qa!</code>: 离开 Vim，(当心，所有的改动都会丢失！)</p><p><code>set nu</code> 或者 <code>set number</code> : vim显示行数</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><p>[1] <a href="https://github.com/yianwillis/vimcdoc" target="_blank" rel="noreferrer">官方中文手册</a></p><p>[2] <a href="https://yianwillis.github.io/vimcdoc/doc/help.html" target="_blank" rel="noreferrer">官方中文手册-总览</a></p><h2 id="随记" tabindex="-1">随记 <a class="header-anchor" href="#随记" aria-label="Permalink to &quot;随记&quot;">​</a></h2><ul><li>-g: E25: GUI cannot be used: Not enabled at compile time</li></ul>`,53)])])}const b=o(d,[["render",t]]);export{m as __pageData,b as default};
